import React, { useState , useEffect} from "react";
import {Link,Routes, Route, Navigate, BrowserRouter} from 'react-router-dom';
import './Design.css';

function Homepage(){
const[gifts,setGifts]=useState([]);
useEffect(()=>{
  fetch("http://localhost:8080/admin/viewGift")
  .then(res=>res.json())
  .then((result)=>{
    setGifts(result);
  }
)
})
return<>

<div class="topnav">
<a className="pad" id="">Curtain Gifts</a> 
        <a id="productHomeButton"> <Link to = "/home" className="link"> Home  </Link> </a>
        <a id="productCartButton"> < Link to = "/user/cart" className="link"> Cart </Link> </a>
        <a id="productOrderButton"> < Link to = "/user/orders" className="link"> Orders </Link> </a>
<a className="padr"> < Link to = "/login" className="link">Logout</Link></a>
</div> 

        <br/>
        <div className="scroll">
        
            {gifts.map(gift => {
            return(
        <div className="space">
                <div className="product"  > 
                    < div  id = {gift.id}> 
                    {gift.imageURL}
                    <t/>                  
                    {gift.giftName} 
                    <t/>
                    {gift.giftPrice}
                    <t/>
                    {gift.giftQuantity}
                    <t/>
                    {gift.giftDesc}
                    <t/>
                    </div>
                </div>
                </div>
            )
        })}
        </div>
</>

}
export default Homepage;
